const raw = $input.first().json.output || '';

// Extract [[LEAD:{...}]] marker if present
const match = raw.match(/\[\[LEAD:(\{.*?\})\]\]/s);

let leadData = null;
if (match) {
  try {
    leadData = JSON.parse(match[1]);
  } catch(e) {
    leadData = null;
  }
}

// Strip the marker from the message sent to customer
const cleanMessage = raw.replace(/\n?\[\[LEAD:\{.*?\}\]\]/s, '').trim();

return [{
  json: {
    agentReply: cleanMessage,
    leadData: leadData,
    hasLead: leadData !== null,
    waId: $('Normalize Input').first().json.from
  }
}];
